INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Persistent Chat & Channels$q$, $q$Organize conversations into teams and channels with threaded replies, reactions, and searchable history.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$HD Video Meetings$q$, $q$Host video calls with screen sharing, recording, live captions, and background effects.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Real-Time Office Co-Authoring$q$, $q$Edit Word, Excel, and PowerPoint files together directly inside chats and channels.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Breakout Rooms$q$, $q$Split larger meetings into smaller discussion groups and bring participants back together.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Teams Phone$q$, $q$Make and receive VoIP calls, transfer calls, and manage voicemail from within Teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$App & Workflow Integrations$q$, $q$Connect third-party apps, bots, and workflows as tabs or notifications within a channel.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Meeting Recording & Transcription$q$, $q$Record meetings and generate transcripts for participants to review afterward.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Together Mode & Custom Layouts$q$, $q$Use immersive meeting views designed to reduce video-call fatigue in large groups.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Admin Controls & Compliance$q$, $q$Manage security policies, data retention, and user access from a centralized admin console.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Deep, native integration with Word, Excel, PowerPoint, and SharePoint$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Free tier available alongside plans bundled into Microsoft 365 subscriptions$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Combines chat, video meetings, calling, and file collaboration in one app$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Strong admin, security, and compliance controls for larger organizations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Works across desktop, web, and mobile with consistent functionality$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Interface can feel dense and overwhelming for teams new to Microsoft 365$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Notification management requires deliberate setup to avoid channel overload$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Less compelling for organizations not already using Microsoft 365 or Office$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Full feature set often requires a paid Microsoft 365 license tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Some users find channel and team structure less intuitive than simpler chat apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Is Microsoft Teams free to use?$q$, $q$Yes, Microsoft Teams offers a free plan with chat, video meetings, and basic file sharing. Additional features and higher usage limits require a paid Microsoft 365 or Teams Essentials plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Do I need Microsoft 365 to use Teams?$q$, $q$No, Teams can be used with the free plan or standalone Teams Essentials without a full Microsoft 365 subscription, though bundled Microsoft 365 plans unlock deeper Office integration.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Can Microsoft Teams replace a phone system?$q$, $q$Yes, with a Teams Phone add-on or included plan, users can make and receive calls, transfer calls, and manage voicemail, functioning as a cloud-based phone system.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Does Teams work on mobile devices?$q$, $q$Yes, Microsoft Teams has apps for iOS and Android that support chat, meetings, calling, and file access alongside the desktop and web clients.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$How does Teams compare to Slack or Zoom?$q$, $q$Teams combines chat similar to Slack and video meetings similar to Zoom into one app, with its main advantage being tighter native integration with Microsoft 365 and Office applications.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Internal Team Communication$q$, $q$Departments and project groups use dedicated channels to chat, share updates, and keep files, tasks, and decisions organized in one searchable place instead of scattered emails.$q$, $q$Internal teams and departments in small and mid-sized businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$External Client Meetings$q$, $q$Organizations schedule and host video calls with clients or partners outside the company, sharing screens, presenting proposals, and recording sessions for later reference.$q$, $q$Client-facing teams such as sales, consulting, and account management$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Hybrid & Remote Work Collaboration$q$, $q$Distributed employees co-author documents in real time, join standups and all-hands meetings from anywhere, and stay connected through persistent chat regardless of location.$q$, $q$Remote and hybrid workforces across geographically dispersed offices$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Classroom & Education Management$q$, $q$Teachers use Teams for Education to run virtual classes, distribute assignments, hold office hours, and communicate with students and parents in a structured environment.$q$, $q$Schools, universities, and educators managing virtual or hybrid classrooms$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Microsoft Teams (Free)$q$, $q$$0$q$, $q$Free forever$q$, $q$["Unlimited chat messages and search","Video meetings for up to 60 minutes","File storage per user","Screen sharing and basic collaboration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Teams Essentials$q$, $q$~$4.00 per user/month$q$, $q$Billed annually$q$, $q$["Longer group meetings and larger meeting sizes","More cloud storage per user","Simplified scheduling and calendar tools","Standalone plan without full Microsoft 365 apps"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Microsoft 365 Business Basic$q$, $q$~$6.00 per user/month$q$, $q$Billed annually$q$, $q$["Teams plus web and mobile versions of Office apps","Business email with Exchange","OneDrive and SharePoint storage","Standard security and compliance tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$Microsoft 365 Business Standard$q$, $q$~$12.50 per user/month$q$, $q$Billed annually$q$, $q$["Everything in Business Basic","Full desktop versions of Word, Excel, and PowerPoint","Advanced meeting features like webinars","Additional collaboration and automation tools"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Microsoft Teams is a communication and collaboration hub that combines persistent chat, video meetings, file sharing, and app integrations into a single workspace. Launched in 2017 as part of the Microsoft 365 suite, it was built to replace scattered email threads and separate meeting tools with one place where conversations, documents, and calendars live together.$q$, $q$At its core, Teams organizes work around teams and channels, giving departments, projects, or clients dedicated spaces for chat, shared files, and tabs that surface tools like Word, Excel, Planner, or third-party apps directly inside the conversation. Meetings, calls, and messaging all run through the same client on desktop, web, and mobile.$q$, $q$Because it ships bundled with Microsoft 365 and Office 365 subscriptions, and also offers a standalone free tier, Teams has become a default choice for organizations already invested in the Microsoft ecosystem, competing directly with Slack for chat and Zoom for video meetings while leaning on its deep Office integration as its main differentiator.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$who-teams-is-for$q$, $q$Who Microsoft Teams Is For$q$, 2, ARRAY[$q$Teams is best suited to organizations that already rely on Microsoft 365, Office apps, SharePoint, or OneDrive, since those users get the most seamless experience: documents open and co-author natively inside chat threads and meetings without switching tools or losing formatting.$q$, $q$It also fits small businesses and enterprises that need one platform to handle internal messaging, external client calls, webinars, and phone-system replacement, as well as schools and universities using Teams for Education for classes, assignments, and virtual office hours.$q$, $q$IT and security teams managing hybrid or remote workforces benefit from Teams' centralized administration, compliance controls, and identity integration with Azure Active Directory, making it easier to enforce policies across an entire organization from one admin console.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations with no existing Microsoft 365 investment may find Teams less compelling, since much of its value comes from tight Office and SharePoint integration; teams built around Google Workspace or fully independent tools may not see the same benefit.$q$, $q$Very small teams or startups that want a lightweight, low-friction chat app with minimal setup might feel Teams is heavier than necessary, particularly if they are not ready to navigate Microsoft 365 licensing tiers to unlock full functionality.$q$, $q$Groups whose primary need is a best-in-class standalone webinar or large-scale event platform, or a highly minimal, distraction-free messaging app, may prefer specialized tools over Teams' broader, more feature-dense approach.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Teams centers on persistent channels and one-on-one or group chat, supporting threaded replies, reactions, file attachments, and searchable history, so conversations stay organized by project or topic rather than buried in a single inbox.$q$, $q$Video meetings support screen sharing, recording, live captions, background blur or replacement, together mode, and breakout rooms for smaller group discussions, along with scheduling directly from Outlook or the Teams calendar and support for large webinars and town halls.$q$, $q$Beyond chat and meetings, Teams enables real-time co-authoring of Word, Excel, and PowerPoint files inside conversations, integrates with hundreds of third-party apps and workflows, and offers Teams Phone for VoIP calling, plus admin controls for security, compliance, and data retention policies.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', $q$the-teams-experience$q$, $q$The Microsoft Teams Experience$q$, 2, ARRAY[$q$Using Teams day to day means navigating a dense interface of teams, channels, chats, calendar, and calls, all accessible from desktop, web browser, and mobile apps. New users familiar with Office generally adapt quickly, while those unfamiliar with Microsoft's ecosystem may need time to learn where features live.$q$, $q$Performance and reliability have improved substantially since the app's early years, with faster load times and a redesigned client, though notification volume across many channels can feel overwhelming without deliberate configuration of alert preferences and channel muting.$q$, $q$Overall, the experience rewards organizations willing to invest in setup and structure, delivering a genuinely unified hub for communication and file work once teams, channels, and permissions are configured thoughtfully around how the organization actually operates.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('38ae237b-78e7-4604-8a45-6bc26a5f678f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
