INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Course Management$q$, $q$Organize content into weekly or topic-based course formats with activities, resources, and conditional release rules.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Quiz Engine$q$, $q$Build assessments with many question types, randomized question banks, timed attempts, and automatic grading.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Gradebook$q$, $q$Combine and weight scores across assignments, quizzes, and activities in a fully configurable grading system.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Forums and Collaboration$q$, $q$Support discussion boards, wikis, and group activities to enable peer interaction within courses.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Plugin Ecosystem$q$, $q$Extend functionality with thousands of community and commercial plugins covering conferencing, analytics, and more.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Mobile App$q$, $q$Access courses, grades, and notifications on the go with the official Moodle Mobile app for iOS and Android.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Web Services API$q$, $q$Integrate Moodle with student information systems, HR platforms, and single sign-on through a documented API.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Multi-language Support$q$, $q$Serve learners in dozens of languages with a fully translatable interface and course content.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Completion Tracking and Reports$q$, $q$Monitor learner progress and engagement with activity logs, completion tracking, and built-in reporting tools.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Themes and Customization$q$, $q$Reskin the platform's look and feel with custom themes to match institutional or organizational branding.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Core software is free and open source with no per-user licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Highly customizable through plugins, themes, and a public web services API$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Strong assessment tools, including a flexible quiz engine and configurable gradebook$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Large global community and network of certified partners for support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Available in dozens of languages, making it suitable for international deployments$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Self-hosting requires ongoing server maintenance, security updates, and technical expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Interface can feel dated compared to newer, consumer-style learning platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Initial setup and configuration have a noticeable learning curve for new administrators$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Deep customization often requires developer resources or a paid Moodle Partner$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$MoodleCloud's free tier has limited users and storage, requiring a paid upgrade for larger deployments$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Is Moodle free to use?$q$, $q$Yes, the core Moodle software is free and open source under the GNU GPL, so you can download, install, and modify it at no cost. Paid options like MoodleCloud hosting or Moodle Partner services are available for organizations that want managed support instead of self-hosting.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$What is MoodleCloud?$q$, $q$MoodleCloud is Moodle HQ's official hosted version of the platform, letting organizations run Moodle without installing or maintaining their own server. It offers a free entry-level tier with limited users and storage, plus paid plans for larger sites.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Do I need technical skills to run Moodle?$q$, $q$Self-hosting Moodle benefits from server administration and PHP/database familiarity, especially for upgrades and custom plugins. Using MoodleCloud or a certified Moodle Partner removes most of that technical burden.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Does Moodle have a mobile app?$q$, $q$Yes, the official Moodle Mobile app is available for iOS and Android, letting students and instructors access courses, grades, and notifications from their phones or tablets.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Can Moodle integrate with other systems?$q$, $q$Yes, Moodle provides a web services API and supports standards like LTI, allowing integration with student information systems, HR platforms, single sign-on providers, and many third-party plugins.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Higher Education Course Delivery$q$, $q$Universities and colleges use Moodle to host lecture materials, assignments, and quizzes for both in-person and fully online degree programs.$q$, $q$Universities and colleges$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$K-12 Virtual Classrooms$q$, $q$School districts deploy Moodle to give teachers a structured space for assignments, grading, and communication with students and parents.$q$, $q$K-12 schools and districts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Corporate Training and Compliance$q$, $q$Companies use Moodle to deliver onboarding, compliance training, and certification courses while tracking completion across employees.$q$, $q$Corporate L&D and HR teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Nonprofit and Government Training Programs$q$, $q$Nonprofits and public agencies rely on Moodle's free core platform to run staff or community training programs on limited budgets.$q$, $q$Nonprofits and government agencies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Self-Hosted Moodle$q$, $q$Free$q$, $q$N/A$q$, $q$["Full open-source source code","Unlimited users and courses","Install on your own server or hosting provider","Complete control over customization and plugins"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$MoodleCloud Free$q$, $q$Free$q$, $q$N/A$q$, $q$["Small user and storage limits","Managed hosting by Moodle HQ","No server maintenance required","Good for testing or very small sites"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$MoodleCloud Paid Tiers$q$, $q$Varies by users and storage$q$, $q$Annual$q$, $q$["Increased user and storage limits","Managed hosting and upgrades","Priority support options","No ads or branding limitations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$Moodle Partner Hosting$q$, $q$Custom$q$, $q$Contract$q$, $q$["Hosting, customization, and support from a certified partner","Custom integrations and plugin development","Service-level agreements for institutions","Migration and training assistance"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Moodle is a free, open-source learning management system originally released in 2002 by Australian educator Martin Dougiamas. Built on PHP and distributed under the GNU General Public License, it lets schools, universities, companies, and government bodies create, deliver, and manage online courses, quizzes, and training programs without paying for a software license, since anyone can download, install, host, and modify the underlying code.$q$, $q$Beyond the free core software, Moodle HQ, headquartered in Perth, Australia, offers MoodleCloud, a hosted version of the platform that removes the need to install and maintain a server yourself. A global network of certified Moodle Partners also provides hosting, integration, customization, and support services for organizations that want professional help running their installation.$q$, $q$Moodle has grown into one of the most widely deployed learning management systems in the world. It powers course delivery for higher education institutions, K-12 schools, corporate training departments, and nonprofits, largely because the software is free to run, translated into dozens of languages, and highly extensible through a large ecosystem of community-built plugins and themes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$who-moodle-is-for$q$, $q$Who Moodle Is For$q$, 2, ARRAY[$q$Moodle is a strong fit for universities, colleges, and school districts that need a flexible course management platform and either already have IT staff to run a server or are willing to use MoodleCloud or a hosting partner. Its granular control over course structure, grading, and enrollment makes it popular with registrars and academic departments managing many concurrent classes.$q$, $q$It also works well for corporate training and compliance teams that need to track completions, certifications, and quiz scores across large workforces, since Moodle's reporting and gradebook tools can be configured to match internal training requirements. Nonprofits and government agencies with tight software budgets are drawn to it because the core platform carries no licensing fee.$q$, $q$Organizations with in-house developers or a budget for a Moodle Partner get the most value, because Moodle's real power comes from customizing themes, connecting plugins, and integrating with existing student information or HR systems. Teams that are comfortable investing time in setup and administration, rather than expecting a fully polished experience out of the box, tend to be the happiest long-term users.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Small teams or solo educators who want a course online in minutes, with no configuration and a modern consumer-style interface, will likely find Moodle's setup and administrative screens more involved than lightweight course-builder tools designed for individual creators.$q$, $q$Organizations without any internal technical capacity and without budget for MoodleCloud or a hosting partner may struggle, since self-hosting Moodle well requires server maintenance, security updates, and periodic upgrades that someone has to own on an ongoing basis.$q$, $q$Teams that primarily want a slick video-course marketplace, a marketing-driven cohort platform, or a simple internal wiki-style knowledge base may be better served by purpose-built alternatives, since Moodle is optimized around structured courses, grading, and academic-style enrollment rather than lightweight content publishing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Moodle organizes learning into courses made up of activities and resources: forums, assignments, quizzes, lessons, wikis, glossaries, and uploaded files, all arranged on a customizable course page. Instructors can set completion rules, release conditions, and grading scales for each activity, giving fine-grained control over how a course unfolds for different learners.$q$, $q$Assessment and tracking are a major strength, with a flexible quiz engine supporting many question types, a configurable gradebook that can weight and combine scores across activities, and completion tracking that shows administrators exactly where each learner stands. Built-in reporting and activity logs help administrators audit engagement and outcomes.$q$, $q$Extensibility rounds out the platform: thousands of community and commercial plugins add features like video conferencing, plagiarism detection, and advanced analytics, while the theme system and web services API let organizations reskin the interface and connect Moodle to student information systems, HR platforms, or single sign-on providers.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da3ec484-b729-46bf-a035-975b4975e2d9', $q$the-moodle-experience$q$, $q$The Moodle Experience$q$, 2, ARRAY[$q$For administrators, the Moodle experience starts with setup: either installing the software on a server, subscribing to MoodleCloud, or working with a Moodle Partner. Once running, the admin area exposes a large number of settings for users, courses, plugins, and site appearance, which gives control but also means there is a learning curve for anyone new to the platform.$q$, $q$For instructors, building a course typically means adding activities and resources to a weekly or topic-based layout, configuring the gradebook, and setting completion rules, after which day-to-day work centers on grading submissions, moderating forums, and monitoring learner progress through built-in reports.$q$, $q$For students, Moodle presents a course dashboard listing enrolled classes, upcoming deadlines, and grades, accessible from a browser or the official Moodle Mobile app for iOS and Android. The interface can look dated compared to newer consumer learning apps, but its consistency and predictability across thousands of institutions is part of why it remains a familiar, trusted experience for millions of learners worldwide.$q$]::text[], 4);
