INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Drag-and-Drop Email Editor$q$, $q$Build responsive, on-brand email campaigns visually using pre-built blocks and templates, with no coding required.$q$, 0);
