INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Landing Pages and Signup Forms$q$, $q$Design landing pages and embeddable forms to capture new leads and grow subscriber lists directly within the platform.$q$, 3);
