INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Real-Time Analytics$q$, $q$Track opens, clicks, unsubscribes, and revenue attribution through built-in reporting dashboards.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$A/B Testing$q$, $q$Test subject lines and campaign content variations to identify what resonates best with subscribers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Personalization Tokens$q$, $q$Insert dynamic subscriber data into campaigns to make messaging feel individually tailored at scale.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Third-Party Integrations$q$, $q$Connect Moosend to CRMs, ecommerce platforms, and other marketing tools to keep subscriber data in sync.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Intuitive drag-and-drop editor that's easy for beginners to pick up$q$, 0);
