INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Feature set can feel narrower than large enterprise marketing clouds$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Pricing scales with list size, which can add up for fast-growing lists$q$, 1);
