INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Some integrations may require workarounds for highly customized tech stacks$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$What is Moosend used for?$q$, $q$Moosend is used for creating and sending email marketing campaigns, building automated workflows, and managing subscriber lists for businesses and ecommerce stores.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Does Moosend offer a free plan or trial?$q$, $q$Moosend has offered a free tier and free trial options in the past for smaller subscriber lists; current availability and limits should be confirmed on moosend.com, as plans can change over time.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Is Moosend good for ecommerce businesses?$q$, $q$Yes, Moosend includes ecommerce-focused features such as abandoned cart automation, product recommendations, and integrations with popular online store platforms.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Does Moosend support marketing automation?$q$, $q$Yes, Moosend provides a visual automation builder that lets users create trigger-based workflows using subscriber behavior such as signups, clicks, and purchases.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Is Moosend part of Sitecore?$q$, $q$Yes, Moosend was acquired by Sitecore and now operates as part of Sitecore's broader marketing and customer experience technology portfolio.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Ecommerce Automated Revenue Flows$q$, $q$Set up abandoned cart reminders, post-purchase follow-ups, and win-back campaigns that run automatically based on shopper behavior.$q$, $q$Ecommerce store owners and online retailers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Newsletter and Content Distribution$q$, $q$Design and send recurring newsletters to a growing subscriber base with segmentation to keep engagement high.$q$, $q$Content creators and newsletter publishers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Lead Capture and Nurture Campaigns$q$, $q$Use landing pages and signup forms to capture new leads, then nurture them through automated email sequences.$q$, $q$Small business owners and marketing generalists$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Multi-Client Campaign Management$q$, $q$Manage email marketing and automation for several client accounts from a single, straightforward platform.$q$, $q$Marketing agencies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Free$q$, $q$$0$q$, $q$monthly$q$, $q$["Limited subscriber count","Email campaign builder","Basic reporting","Signup forms"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Pro$q$, $q$From ~$9/month$q$, $q$monthly (based on subscriber count)$q$, $q$["Unlimited emails","Marketing automation workflows","Landing pages","A/B testing","Transactional emails"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$custom$q$, $q$["Dedicated account management","Custom onboarding","Advanced deliverability support","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Moosend is an email marketing and marketing automation platform designed to help businesses create, send, and optimize campaigns without needing a dedicated technical team. It combines a drag-and-drop email builder, subscriber list management, and visual automation workflows into a single, approachable interface, and it is now part of Sitecore's broader marketing technology portfolio.$q$, $q$The platform's core appeal is its balance of simplicity and depth. Beginners can get a campaign out the door quickly using pre-built templates, while more advanced marketers can build multi-step automation sequences, segment audiences based on behavior, and track performance through built-in analytics. This flexibility has made Moosend popular with small and mid-sized businesses, ecommerce stores, and agencies managing multiple client accounts.$q$, $q$Beyond email, Moosend also offers landing page and signup form builders, letting users capture leads and grow their subscriber lists without relying on separate tools. The overall positioning is that of an affordable, all-in-one alternative to larger email marketing suites, aimed at teams that want solid automation capabilities without a steep learning curve or enterprise-level price tag.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$who-moosend-is-for$q$, $q$Who Moosend Is For$q$, 2, ARRAY[$q$Moosend is well suited to small and medium-sized businesses that need reliable email marketing without a large budget or a specialized marketing operations team. Solo founders, marketing generalists, and small in-house teams tend to appreciate how quickly they can get a first campaign live using the visual editor and existing templates.$q$, $q$Ecommerce brands are another strong fit, since Moosend supports product recommendations, abandoned cart flows, and integrations with popular store platforms, helping online sellers automate recurring revenue-generating emails like win-back sequences and post-purchase follow-ups. Agencies that manage email marketing for several clients also gravitate toward Moosend because of its straightforward account structure and reasonable per-subscriber pricing.$q$, $q$It also works well for content creators, newsletter publishers, and community builders who mainly need dependable list management, good deliverability, and simple automation rather than a sprawling customer data platform. For these users, Moosend offers enough sophistication to grow into without the complexity overhead of enterprise marketing suites.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex, multi-channel marketing operations spanning SMS, push notifications, in-app messaging, and deep CRM integration may find Moosend's feature set narrower than dedicated enterprise marketing clouds. Organizations that already run heavily customized workflows across many departments might outgrow it faster than expected.$q$, $q$Teams that require highly granular, code-level control over every aspect of email rendering, or that need extensive built-in A/B testing sophistication and predictive analytics comparable to the biggest players in the space, may find Moosend's tooling more limited by comparison. Businesses with very large, fast-growing lists should also carefully model pricing tiers in advance, since subscriber-based pricing can climb as lists scale.$q$, $q$Additionally, companies that need a single platform to unify email with advanced SMS marketing, dedicated CRM pipelines, or complex e-commerce personalization at scale may prefer a broader martech suite. Moosend is best approached as a focused email and automation tool rather than an all-purpose customer engagement platform.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Moosend provides a drag-and-drop email designer with a library of responsive templates, making it easy to produce on-brand campaigns without design or coding experience. Alongside this sits a visual automation builder, where users can create workflows triggered by subscriber behavior, such as signups, purchases, link clicks, or inactivity.$q$, $q$List management tools allow for segmentation based on demographics, engagement history, and custom fields, so campaigns can be targeted more precisely. Moosend also includes landing page and signup form builders, real-time analytics dashboards covering opens, clicks, and revenue attribution, and an array of integrations with ecommerce platforms, CRMs, and other marketing tools.$q$, $q$Additional capabilities include A/B testing for subject lines and content, personalization tokens, product recommendation blocks for online stores, and a reporting suite that helps teams understand which campaigns and automations are actually driving engagement and sales over time.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5bf89844-295b-44a9-b875-c4f86ae4f19d', $q$the-moosend-experience$q$, $q$The Moosend Experience$q$, 2, ARRAY[$q$Day to day, using Moosend feels straightforward: the dashboard surfaces campaigns, automations, and lists in a clear layout, and the editor itself is responsive enough that building and previewing a campaign rarely feels tedious. New users generally find the onboarding curve gentle, since most actions map closely to what marketers already expect from an email tool.$q$, $q$The automation workflow builder is often highlighted as a highlight of the experience, letting users visually map out sequences of triggers, conditions, and actions without writing any code. This makes it approachable for non-technical marketers while still offering enough branching logic to support fairly sophisticated customer journeys.$q$, $q$Support and documentation are geared toward practical, task-based help, which suits the platform's target audience of small and mid-sized teams. Overall, the experience is less about flashy extras and more about dependable execution: getting emails designed, automated, and delivered without unnecessary friction along the way.$q$]::text[], 4);
