INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Keyword Explorer$q$, $q$Research keyword volume, difficulty, and SERP features, plus related terms and questions, to prioritize realistic content and ranking targets.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Rank Tracking$q$, $q$Track keyword positions across search engines, devices, and locations, and monitor visibility trends against tracked competitors over time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Site Crawl (Site Audit)$q$, $q$Continuously scan a domain for technical SEO issues like broken links, duplicate content, and metadata problems, prioritized by impact.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Link Explorer$q$, $q$Analyze backlink profiles for any domain, including link sources, anchor text, and Moz's Domain Authority, Page Authority, and Spam Score.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$MozBar$q$, $q$A free browser extension that surfaces Domain Authority, Page Authority, and on-page SEO elements for any page while browsing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$On-Page Optimization Grader$q$, $q$Grade individual pages against target keywords and get specific recommendations for improving on-page SEO elements.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Custom Reporting & Dashboards$q$, $q$Build branded, campaign-based reports that summarize rankings, site health, and link growth for stakeholders or clients.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Competitive Research$q$, $q$Compare keyword rankings, link profiles, and site health against competitor domains within the same campaign view.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Moz Links API$q$, $q$Access Moz's link and authority data programmatically for integration into custom tools, dashboards, or internal reporting systems.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Well-known Domain Authority and Page Authority metrics widely referenced across the SEO industry$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$All-in-one suite covering keyword research, rank tracking, site audits, and link analysis in one dashboard$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Free MozBar browser extension for quick on-page metric checks outside the main platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Site Crawl reports pair issues with clear, prioritized fixes for less experienced users$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Strong educational content, including the Moz blog and Whiteboard Friday, supports the product's learning curve$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Tracked-keyword and crawl allowances on lower-tier plans can feel restrictive for larger sites$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Link index is sometimes viewed as smaller than those of competitors like Ahrefs or Semrush$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$No permanent free plan for the full Pro suite, only a limited-time free trial$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Interface and reporting can feel less data-dense than newer, power-user-focused SEO tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Some advanced needs, like enterprise rank tracking or local listing management, require separate Moz products$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Does Moz Pro have a free plan?$q$, $q$Moz Pro itself is a paid subscription with a free trial rather than a permanent free tier, though Moz offers standalone free tools such as the MozBar browser extension and a free Domain Authority checker.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$What is Domain Authority, and how is it used in Moz Pro?$q$, $q$Domain Authority is a proprietary Moz metric that scores a website's likelihood of ranking well in search results relative to other sites, and it appears throughout Moz Pro alongside Page Authority as a quick way to gauge relative site strength.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Can Moz Pro track local search rankings?$q$, $q$Moz Pro supports rank tracking across specific locations and devices for local and organic terms, and it can be paired with Moz Local, a separate Moz product focused on local listing management.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Does Moz Pro offer an API?$q$, $q$Yes, Moz provides APIs, including the Moz Links API, that let developers pull authority and link data directly into custom tools, internal dashboards, or third-party integrations.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$How does Moz Pro compare to tools like Ahrefs or Semrush?$q$, $q$Moz Pro covers the same core pillars of keyword research, rank tracking, audits, and link analysis, but it's generally seen as more beginner-friendly and education-focused, while some competitors offer larger link indexes or deeper technical crawling for large-scale sites.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Monthly SEO performance reporting$q$, $q$In-house marketers use campaign dashboards and custom reports to summarize ranking changes, site health, and link growth for leadership review.$q$, $q$In-house marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Multi-client SEO management$q$, $q$Agencies run separate Moz Pro campaigns per client domain, tracking rankings and backlinks and exporting branded reports for client meetings.$q$, $q$Digital marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Content and keyword planning$q$, $q$Content teams use Keyword Explorer's volume and difficulty scores to prioritize topics and build content around realistically winnable search terms.$q$, $q$Content marketers and bloggers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Technical SEO and link audits$q$, $q$SEO specialists use Site Crawl and Link Explorer to find crawl errors, broken links, and backlink profile issues that could be limiting organic visibility.$q$, $q$SEO specialists and technical marketers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Standard$q$, $q$From $49/month$q$, $q$Monthly, with a discount for annual billing$q$, $q$["Core keyword research and rank tracking","Site Crawl technical audits","Link Explorer backlink data","Limited number of tracked keywords and campaigns"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Medium$q$, $q$Mid-tier pricing above Standard$q$, $q$Monthly, with a discount for annual billing$q$, $q$["Higher tracked-keyword and campaign limits","Expanded Site Crawl page allowances","Additional reporting options","Priority customer support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Large$q$, $q$Higher tier above Medium$q$, $q$Monthly, with a discount for annual billing$q$, $q$["Further increased keyword, campaign, and crawl limits","Deeper competitive research allowances","Team collaboration features","Access to Moz's full reporting suite"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$Premium$q$, $q$Top-tier pricing above Large$q$, $q$Monthly, with a discount for annual billing$q$, $q$["Highest tracked-keyword and crawl allowances","Maximum campaign and user seats","Advanced API access limits","Dedicated onboarding and support resources"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Moz Pro is the all-in-one SEO platform built by Moz, one of the pioneering companies in the search marketing industry. Founded in 2004 and headquartered in Seattle, Washington, Moz helped popularize concepts like Domain Authority that are still referenced across the SEO world today, and Moz Pro packages the company's research tools into a single subscription rather than a scattered set of standalone utilities.$q$, $q$The suite centers on four core workflows: keyword research, rank tracking, technical site audits, and backlink analysis, all tied together inside campaign-based dashboards organized around a domain. Rather than forcing users to stitch together separate tools for each task, Moz Pro consolidates the data marketers need to plan content, monitor visibility, and fix crawl issues from one login, with shared metrics carrying across every module.$q$, $q$Moz has also built a reputation around SEO education, publishing extensive guides and the long-running Whiteboard Friday video series, and that philosophy shapes how Moz Pro itself is designed for newcomers. The interface leans toward approachability over raw data density, pairing metrics with plain-language explanations so less experienced marketers can interpret scores like Domain Authority or Page Authority without needing a dedicated in-house SEO specialist on staff.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$who-moz-pro-is-for$q$, $q$Who Moz Pro Is For$q$, 2, ARRAY[$q$Moz Pro fits in-house marketing teams and solo SEO practitioners who want one subscription that covers keyword research, rank tracking, and site audits instead of piecing together multiple point solutions. Its guided recommendations, glossary-style explanations, and prioritized task lists make it a practical entry point for marketers who are actively building their SEO literacy alongside day-to-day campaign work.$q$, $q$Content marketers and bloggers who need to prioritize topics benefit from Keyword Explorer's difficulty and opportunity scoring, which helps identify realistic keyword targets rather than only chasing the highest-volume terms. Small businesses managing their own organic and local visibility can also use Moz Pro to keep tabs on rankings and site health without hiring an outside agency to interpret the numbers for them.$q$, $q$Agencies handling several client accounts are a strong fit too, since campaigns can be organized per domain with custom, brandable reports that summarize ranking movement, site health, and link growth for client meetings. Teams that value Moz's long-standing Domain Authority metric as a shorthand talking point with clients often keep Moz Pro specifically for that name recognition and credibility.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises and publishers with sprawling, high-volume keyword portfolios or backlink profiles may find Moz Pro's tracked-keyword allowances and link index size limiting compared to tools built specifically for that scale, and often end up pairing Moz Pro with, or replacing it with, heavier enterprise-grade platforms once their programs mature.$q$, $q$Teams that need to crawl and audit very large sites, running into the millions of URLs, with deep log-file analysis or highly customizable crawl rules, may find Site Crawl less exhaustive than dedicated technical crawlers, and should evaluate specialized crawling software alongside or instead of Moz Pro for that specific, high-volume use case.$q$, $q$Hobby bloggers or very early-stage sites with minimal budget and only occasional rank-checking needs may not get enough ongoing value from a recurring subscription, and could rely instead on Moz's free MozBar extension or other lightweight free tools until their SEO program grows large enough to justify a paid, full-suite subscription.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Keyword Explorer is the research engine, surfacing search volume estimates, keyword difficulty, organic click-through-rate signals, and SERP feature analysis so users can prioritize which terms are realistically winnable for their domain's current authority level. It also groups related keywords and suggests related questions and topics, widening content planning beyond a single seed term into a fuller content cluster.$q$, $q$Rank Tracking monitors keyword positions across search engines, devices, and locations, rolling results up into visibility trend charts so teams can see whether a domain is gaining or losing ground over time relative to tracked competitors. Site Crawl continuously scans a domain for technical issues like broken links, duplicate content, redirect chains, and missing metadata, then prioritizes fixes by their estimated impact.$q$, $q$Link Explorer provides backlink data alongside Moz's proprietary Domain Authority, Page Authority, and Spam Score metrics, letting users evaluate their own link profile and research where competitors are earning their links. The free MozBar browser extension surfaces these same core metrics on any page while browsing, and custom, campaign-level reporting ties all of this data together into shareable dashboards and exports.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', $q$the-moz-pro-experience$q$, $q$The Moz Pro Experience$q$, 2, ARRAY[$q$Getting started involves creating a campaign around a domain, adding target keywords and competitor domains, and letting Moz Pro's crawlers begin gathering ranking and site health data, with most of the dashboard populating meaningfully within the first few days of setup. The onboarding flow is guided step-by-step, which keeps the initial learning curve manageable even for first-time SEO users.$q$, $q$Day-to-day use centers on the campaign dashboard, where ranking changes, crawl issues, and link movement are summarized visually with short explanations attached to each score, reflecting Moz's education-first philosophy throughout the product. Users who want deeper analysis can drill into Keyword Explorer or Link Explorer directly, independent of any specific campaign, for one-off research on new domains or topics.$q$, $q$Support resources include the Moz Help Hub, an active community forum, and the broader Moz blog, all of which help fill in context when a metric or report needs more explanation than the in-app tooltips provide. Overall, the experience favors clarity and hand-holding guidance over the denser, more technical interfaces found in some competing SEO suites aimed at power users.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ed5feb5f-02cf-4bc0-a6b1-e14c52f7aab2', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
